--!strict
local function rarity(frame:string,background:string,animation:string,glow:string,border:string,particles:string):any return table.freeze({frame=frame,background=background,animation=animation,glow=glow,border=border,particles=particles})end
local rarities={Common=rarity("MatteGray","Graphite","None","Muted","Single","None"),Bronze=rarity("BronzeMetal","BronzeDark","Shine","Bronze","Double","SparksLow"),Silver=rarity("SilverMetal","SilverDark","Shine","Silver","Double","SparksLow"),Gold=rarity("GoldMetal","GoldDark","Sweep","Gold","Double","Sparks"),Rare=rarity("GreenGold","BlackGreen","Pulse","ElectricGreen","Electric","Energy"),Elite=rarity("PurpleGreen","PurpleBlack","Pulse","NeonGreen","Electric","Energy"),Legendary=rarity("BlackGold","Black","Lightning","Gold","Electric","LightningLow"),Icon=rarity("WhiteGold","PrestigeWhite","Sweep","WarmWhite","Double","Prestige"),Mythic=rarity("BlackNeon","PureBlack","Lightning","NeonGreen","Electric","Lightning")}
return table.freeze({Valid=table.freeze({Common=true,Bronze=true,Silver=true,Gold=true,Rare=true,Elite=true,Legendary=true,Icon=true,Mythic=true}),Visuals=table.freeze(rarities),Order=table.freeze({"Common","Bronze","Silver","Gold","Rare","Elite","Legendary","Icon","Mythic"})})
